from flask import Flask, request, jsonify
import jwt
import requests
from urllib.parse import urljoin

app = Flask(__name__)

BACKEND_BASE_URL = "http://localhost:5001"

HOP_BY_HOP_HEADERS = {
    "connection",
    "keep-alive",
    "proxy-authenticate",
    "proxy-authorization",
    "te",
    "trailers",
    "transfer-encoding",
    "upgrade",
    "host",
    "content-length",
}

def extract_bearer_token(auth_header):
    if not auth_header:
        return None
    parts = auth_header.split(None, 1)
    if len(parts) != 2 or parts[0].lower() != "bearer":
        return None
    return parts[1].strip()

def validate_jwt(token):
    try:
        claims = jwt.decode(
            token,
            options={
                "verify_signature": True,
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
                "require": ["exp"],
            },
            algorithms=["HS256", "RS256"],
        )
        return claims, None
    except jwt.PyJWTError as e:
        return None, str(e)

def build_forward_headers(claims):
    headers = {}
    for key, value in request.headers.items():
        if key.lower() not in HOP_BY_HOP_HEADERS and key.lower() != "authorization":
            headers[key] = value
    headers["X-User-Claims"] = jwt.encode(claims, "internal-forwarding-secret", algorithm="HS256")
    if "sub" in claims:
        headers["X-User-Id"] = str(claims["sub"])
    if "email" in claims:
        headers["X-User-Email"] = str(claims["email"])
    if "scope" in claims:
        headers["X-User-Scope"] = str(claims["scope"])
    return headers

def forward_request(path, claims):
    target_url = urljoin(BACKEND_BASE_URL.rstrip("/") + "/", path)
    headers = build_forward_headers(claims)

    data = request.get_data()
    params = request.args

    resp = requests.request(
        method=request.method,
        url=target_url,
        headers=headers,
        params=params,
        data=data,
        cookies=request.cookies,
        allow_redirects=False,
        timeout=30,
    )

